<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bots</title>
<style>
  body{font-family:sans-serif;margin:0;padding:20px;background:#222;color:#eee;}
  #hud{display:flex;gap:20px;margin-bottom:10px;}
  #maze{border:2px solid #555;background:#111;}
  button{padding:5px 10px;font-size:1rem;}
</style>
</head>
<body>

<div id="hud">
  <div>Completed: <span id="completed">0</span>/24</div>
  <div>Time: <span id="timer">00:00.000</span></div>
  <button id="reset">Reset</button>
</div>

<canvas id="maze" width="400" height="400"></canvas>

<script>
(() => {
  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  const CELL_SIZE = 20; // 20px per cell
  const COLS = 20;
  const ROWS = 20;

  // Maze data structures
  const maze = Array.from({length:ROWS}, () => Array(COLS).fill(null));
  let spawnCell, exitCell;

  function initMaze() {
    for (let r=0;r<ROWS;r++) for(let c=0;c<COLS;c++)
      maze[r][c] = {n:true,e:true,s:true,w:true,visited:false};
    // Recursive backtracker
    const stack=[];
    let current={r:0,c:0};
    maze[0][0].visited=true;
    while(true){
      const neighbors=[];
      if(current.r>0 && !maze[current.r-1][current.c].visited) neighbors.push({dr:-1,dc:0,n:'n',op:'s'});
      if(current.c<COLS-1 && !maze[current.r][current.c+1].visited) neighbors.push({dr:0,dc:1,n:'e',op:'w'});
      if(current.r<ROWS-1 && !maze[current.r+1][current.c].visited) neighbors.push({dr:1,dc:0,n:'s',op:'n'});
      if(current.c>0 && !maze[current.r][current.c-1].visited) neighbors.push({dr:0,dc:-1,n:'w',op:'e'});
      if(neighbors.length){
        const n=neighbors[Math.floor(Math.random()*neighbors.length)];
        maze[current.r][current.c][n.n]=false;
        maze[current.r+n.dr][current.c+n.dc][n.op]=false;
        stack.push(current);
        current={r:current.r+n.dr,c:current.c+n.dc};
        maze[current.r][current.c].visited=true;
      }else if(stack.length){
        current=stack.pop();
      }else break;
    }
    // Define spawn and exit
    spawnCell = {x:0,y:0};
    exitCell  = {x:COLS-1,y:ROWS-1};
  }

  // Precompute shortest path from spawn to exit using BFS
  const pathCells=[];
  function computePath(){
    const queue=[[spawnCell.x,spawnCell.y]];
    const prev=Array.from({length:ROWS},()=>Array(COLS).fill(null));
    const visited=Array.from({length:ROWS},()=>Array(COLS).fill(false));
    visited[0][0]=true;
    while(queue.length){
      const [x,y]=queue.shift();
      if(x===exitCell.x && y===exitCell.y) break;
      const dirs=[{dx:0,dy:-1,n:'n'}, {dx:1,dy:0,n:'e'}, {dx:0,dy:1,n:'s'}, {dx:-1,dy:0,n:'w'}];
      for(const d of dirs){
        if(!maze[y][x][d.n]) continue;
        const nx=x+d.dx, ny=y+d.dy;
        if(nx<0||nx>=COLS||ny<0||ny>=ROWS) continue;
        if(visited[ny][nx]) continue;
        visited[ny][nx]=true;
        prev[ny][nx]={x,y};
        queue.push([nx,ny]);
      }
    }
    // Reconstruct path
    let cur=exitCell;
    while(cur){
      pathCells.unshift({x:cur.x,y:cur.y});
      cur=prev[cur.y][cur.x];
    }
  }

  // Bot definition
  const BOT_COUNT=24;
  const bots=[];
  function initBots(){
    for(let i=0;i<BOT_COUNT;i++){
      bots.push({
        id:i,
        idx:-i, // negative offset to stagger start
        color:`hsl(${(i*360/BOT_COUNT)%360},70%,60%)`,
        finished:false
      });
    }
  }

  // Rendering
  function draw(){
    ctx.fillStyle='#111';
    ctx.fillRect(0,0,COLS*CELL_SIZE,ROWS*CELL_SIZE);
    // Walls
    ctx.strokeStyle='#555';
    ctx.lineWidth=2;
    for(let r=0;r<ROWS;r++){
      for(let c=0;c<COLS;c++){
        const cell=maze[r][c];
        const x=c*CELL_SIZE,y=r*CELL_SIZE;
        if(cell.n){
          ctx.beginPath();ctx.moveTo(x,y);ctx.lineTo(x+CELL_SIZE,y);ctx.stroke();
        }
        if(cell.e){
          ctx.beginPath();ctx.moveTo(x+CELL_SIZE,y);ctx.lineTo(x+CELL_SIZE,y+CELL_SIZE);ctx.stroke();
        }
      }
    }
    // Exit line
    ctx.fillStyle='#0a0';
    ctx.fillRect(exitCell.x*CELL_SIZE,exitCell.y*CELL_SIZE,CELL_SIZE,CELL_SIZE);
    // Bots
    for(const bot of bots){
      const pos=pathCells[bot.idx>=0?bot.idx:0];
      if(!pos) continue;
      const cx=(pos.x+0.5)*CELL_SIZE;
      const cy=(pos.y+0.5)*CELL_SIZE;
      ctx.fillStyle=bot.color;
      ctx.beginPath();ctx.arc(cx,cy,CELL_SIZE/4,0,Math.PI*2);ctx.fill();
    }
  }

  // Game state
  let startTime=null;
  let elapsedMs=0;
  let completed=0;

  function updateHUD(){
    completedEl.textContent=completed;
    const ms=Math.floor(elapsedMs);
    const s=Math.floor(ms/1000).toString().padStart(2,'0');
    const m=Math.floor((ms%1000)/10).toString().padStart(3,'0');
    timerEl.textContent=`${s}:${m}`;
  }

  function tickStep(){
    for(const bot of bots){
      if(bot.finished) continue;
      if(bot.idx<0){bot.idx++;continue;}
      if(bot.idx < pathCells.length-1){
        bot.idx++;
        if(bot.idx===pathCells.length-1){
          bot.finished=true;
          completed++;
        }
      }
    }
  }

  function tick(n){
    for(let i=0;i<n;i++) tickStep();
    updateHUD();
    draw();
  }

  function reset(){
    initMaze(); computePath(); initBots();
    startTime = performance.now();
    elapsedMs = 0;
    completed = 0;
    updateHUD();
    draw();
  }

  // Animation loop
  function animate(){
    const now=performance.now();
    elapsedMs = now - startTime;
    updateHUD();
    tick(1);
    requestAnimationFrame(animate);
  }

  resetBtn.addEventListener('click',reset);

  // Expose API
  window.game={
    get bots(){return bots.map(b=>({x:pathCells[b.idx>=0?b.idx:0].x,y:pathCells[b.idx>=0?b.idx:0].y}));},
    get completed(){return completed;},
    get elapsedMs(){return elapsedMs;},
    tick,
    reset
  };

  // Start
  reset();
  requestAnimationFrame(animate);
})();
</script>
</body>
</html>
